function cli (args) {
  const opts = parseArgs(args, {
    options: {
      integrate: { type: 'boolean' }
    }
  })
  const dir = opts._[0]

  if (dir && existsSync(dir)) {
    if (dir !== '.' && dir !== './') {
      log('error', 'directory ' + opts._[0] + ' already exists')
      process.exit(1)
    }
  }
  if (dir === undefined) {
    log('error', 'must specify a directory to \'fastify generate\'')
    process.exit(1)
  }
  if (!opts.integrate && existsSync(path.join(dir, 'package.json'))) {
    log('error', 'a package.json file already exists in target directory. retry with the --integrate flag to proceed')
    process.exit(1)
  }

  generate(dir, pluginTemplate).catch(function (err) {
    if (err) {
      log('error', err.message)
      process.exit(1)
    }
  })
}

async function runFastify (opts) {
  loadEnvQuitely()

  let file = null

  try {
    file = await requireServerPluginFromPath(opts._[0])
  } catch (e) {
    return module.exports.stop(e)
  }

  const fastify = Fastify(opts.options)

  const pluginOptions = {}
  if (opts.prefix) {
    pluginOptions.prefix = opts.prefix
  }

  await fastify.register(file, pluginOptions)
  await fastify.ready()
  log('debug', fastify.printRoutes({
    method: opts.method,
    commonPrefix: opts.commonPrefix,
    includeHooks: opts.includeHooks
  }))

  return fastify
}

